joi_block.script:
t1 = (#TemperatureSensor #WineCellar).temperatureSensor_temperature
delay(1 HOUR)
t2 = (#TemperatureSensor #WineCellar).temperatureSensor_temperature
diff = t2 - t1
if (diff < 0) {
diff = t1 - t2
}
if (diff >= 2) {
(#Speaker #LivingRoom).speaker_speak("The wine cellar temperature rose by at least 2 degrees.")
}

